const cfg = $input.first().json;

async function tryPing(url) {
  try {
    await this.helpers.httpRequest({
      method: 'GET',
      url: `${url}/status`,
      timeout: 2000
    });
    return true;
  } catch (e) {
    return false;
  }
}

// 1. Tenta acessar via localhost (Funciona no Windows Local/Nativo)
let worker_url = 'http://127.0.0.1:8000';
let isAlive = await tryPing(worker_url);

// 2. Se falhar, tenta host.docker.internal (Funciona quando n8n está no Docker)
if (!isAlive) {
  worker_url = 'http://host.docker.internal:8000';
  isAlive = await tryPing(worker_url);
}

// 3. Se falhar, tenta o IP da rede local como último recurso
if (!isAlive) {
  worker_url = 'http://192.168.15.35:8000';
  isAlive = await tryPing(worker_url);
}

if (!isAlive) {
  worker_url = 'http://10.233.10.229:8000';
  isAlive = await tryPing(worker_url);
}

if (!isAlive) {
  throw new Error(`
    O SERVIDOR PYTHON NÃO ESTÁ RODANDO! 
    Por favor, abra um terminal na pasta do projeto e digite: python main.py --server
  `);
}

return [{
  json: {
    ...cfg,
    python_worker_url: worker_url,
    host_detectado: worker_url
  }
}];

const cfg = $items('Detectar Ambiente Automático')[0].json;
const baseUrl = cfg.python_worker_url;
const maxAttempts = 720; // 720 * 10s = 2 horas máximo
const delayMs = 10000; // 10 segundos entre checagens

function delay(ms) { return new Promise(resolve => setTimeout(resolve, ms)); }

async function getStatus() {
  return await this.helpers.httpRequest({
    method: 'GET',
    url: `${baseUrl}/status`,
    json: true
  });
}

let finalStatus = null;

for (let i = 0; i < maxAttempts; i++) {
  try {
    const res = await getStatus.call(this);
    if (res.status === 'done' || res.status === 'error') {
      finalStatus = res;
      break;
    }
  } catch (err) {
    // ignora erro de rede temporário
  }
  await delay(delayMs);
}

if (!finalStatus) throw new Error('Timeout esperando o Python Worker');
if (finalStatus.status === 'error') throw new Error(`Erro no Python Worker: ${finalStatus.message}`);

return [{ json: { status: 'SUCESSO', worker_response: finalStatus } }];
